mapper.select:
SELECT 
FROM vso_order_vehicle_snapshot t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.order_id = #{orderId}


    AND t.sale_model_code = #{saleModelCode}


    AND t.configuration_code = #{configurationCode}

ORDER BY t.id DESC

